package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"

	genericapirequest "k8s.io/apiserver/pkg/endpoints/request"
)

// mockTransformer is a test mock that implements the Transformer interface
type mockTransformer struct {
	transformFromStorageResult []byte
	transformFromStorageStale  bool
	transformFromStorageErr    error
	transformToStorageResult   []byte
	transformToStorageErr      error
	recordedFromData           []byte
	recordedToData             []byte
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) (out []byte, stale bool, err error) {
	m.recordedFromData = data
	return m.transformFromStorageResult, m.transformFromStorageStale, m.transformFromStorageErr
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) (out []byte, err error) {
	m.recordedToData = data
	return m.transformToStorageResult, m.transformToStorageErr
}

// TestDefaultContext_AuthenticatedData tests the DefaultContext implementation
func TestDefaultContext_AuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		data     []byte
		expected []byte
	}{
		{
			name:     "non-empty data",
			data:     []byte("some data"),
			expected: []byte("some data"),
		},
		{
			name:     "empty data",
			data:     []byte{},
			expected: []byte{},
		},
		{
			name:     "nil data",
			data:     nil,
			expected: nil,
		},
		{
			name:     "binary data",
			data:     []byte{0x00, 0x01, 0x02, 0xff},
			expected: []byte{0x00, 0x01, 0x02, 0xff},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := DefaultContext(tc.data)
			result := ctx.AuthenticatedData()
			if !bytes.Equal(result, tc.expected) {
				t.Errorf("expected %v, got %v", tc.expected, result)
			}
		})
	}
}

// TestTransformerRoundTrip tests basic round-trip transformation
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name     string
		input    []byte
		outData  []byte
		outErr   error
		expectOk bool
	}{
		{
			name:     "successful transformation",
			input:    []byte("original"),
			outData:  []byte("transformed"),
			outErr:   nil,
			expectOk: true,
		},
		{
			name:     "transformation with error",
			input:    []byte("original"),
			outData:  nil,
			outErr:   fmt.Errorf("transformation failed"),
			expectOk: false,
		},
		{
			name:     "empty input",
			input:    []byte{},
			outData:  []byte("result"),
			outErr:   nil,
			expectOk: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			mock := &mockTransformer{
				transformFromStorageResult: tc.outData,
				transformFromStorageErr:    tc.outErr,
			}

			result, _, err := mock.TransformFromStorage(context.Background(), tc.input, nil)

			if (err == nil) != tc.expectOk {
				t.Errorf("expected error state %v, got %v", tc.expectOk, err == nil)
			}

			if !bytes.Equal(result, tc.outData) {
				t.Errorf("expected %v, got %v", tc.outData, result)
			}

			if !bytes.Equal(mock.recordedFromData, tc.input) {
				t.Errorf("expected to record input %v, got %v", tc.input, mock.recordedFromData)
			}
		})
	}
}

// TestPrefixTransformerWithEmptyData tests behavior with empty data
func TestPrefixTransformerWithEmptyData(t *testing.T) {
	testErr := fmt.Errorf("no match")
	mock := &mockTransformer{
		transformFromStorageResult: []byte("result"),
		transformFromStorageErr:    nil,
	}

	transformers := []PrefixTransformer{
		{Prefix: []byte("prefix:"), Transformer: mock},
	}

	p := NewPrefixTransformers(testErr, transformers...)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	// Empty data should not match any prefix
	result, _, err := p.TransformFromStorage(ctx, []byte{}, nil)

	if result != nil {
		t.Errorf("expected nil result for empty data, got %v", result)
	}

	if err != testErr {
		t.Errorf("expected test error, got %v", err)
	}
}

// TestPrefixTransformerWithNilContext tests behavior when Context is nil
func TestPrefixTransformerWithNilContext(t *testing.T) {
	mock := &mockTransformer{
		transformFromStorageResult: []byte("result"),
		transformFromStorageErr:    nil,
	}

	transformers := []PrefixTransformer{
		{Prefix: []byte("prefix:"), Transformer: mock},
	}

	testErr := fmt.Errorf("no match")
	p := NewPrefixTransformers(testErr, transformers...)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	// Should handle nil Context without panic
	result, _, err := p.TransformFromStorage(ctx, []byte("prefix:data"), nil)

	if err != nil {
		t.Errorf("unexpected error: %v", err)
	}

	if !bytes.Equal(result, []byte("result")) {
		t.Errorf("expected result, got %v", result)
	}
}

// TestPrefixTransformerErrorPropagation tests error propagation through transformers
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	testErr := fmt.Errorf("no match")
	transformErr := fmt.Errorf("encryption error")

	mock := &mockTransformer{
		transformFromStorageErr: transformErr,
	}

	transformers := []PrefixTransformer{
		{Prefix: []byte("prefix:"), Transformer: mock},
	}

	p := NewPrefixTransformers(testErr, transformers...)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	result, _, err := p.TransformFromStorage(ctx, []byte("prefix:data"), nil)

	if result != nil {
		t.Errorf("expected nil result on error, got %v", result)
	}

	if err != transformErr {
		t.Errorf("expected encryption error, got %v", err)
	}
}

// TestPrefixTransformerWithMultiplePrefixes tests prefix matching with multiple transformers (table-driven)
func TestPrefixTransformerWithMultiplePrefixes(t *testing.T) {
	testErr := fmt.Errorf("no matching transformer")

	testCases := []struct {
		name          string
		input         []byte
		transformers  []PrefixTransformer
		expectedData  []byte
		expectedStale bool
		expectedErr   error
	}{
		{
			name:  "first transformer matches",
			input: []byte("first:data"),
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("first:"),
					Transformer: &mockTransformer{
						transformFromStorageResult: []byte("result1"),
					},
				},
				{
					Prefix: []byte("second:"),
					Transformer: &mockTransformer{
						transformFromStorageResult: []byte("result2"),
					},
				},
			},
			expectedData:  []byte("result1"),
			expectedStale: false,
			expectedErr:   nil,
		},
		{
			name:  "second transformer matches",
			input: []byte("second:data"),
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("first:"),
					Transformer: &mockTransformer{
						transformFromStorageResult: []byte("result1"),
					},
				},
				{
					Prefix: []byte("second:"),
					Transformer: &mockTransformer{
						transformFromStorageResult: []byte("result2"),
					},
				},
			},
			expectedData:  []byte("result2"),
			expectedStale: true, // not the first transformer
			expectedErr:   nil,
		},
		{
			name:  "no transformer matches",
			input: []byte("unknown:data"),
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("first:"),
					Transformer: &mockTransformer{
						transformFromStorageResult: []byte("result1"),
					},
				},
			},
			expectedData:  nil,
			expectedStale: false,
			expectedErr:   testErr,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			p := NewPrefixTransformers(testErr, tc.transformers...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

			result, stale, err := p.TransformFromStorage(ctx, tc.input, nil)

			if !bytes.Equal(result, tc.expectedData) {
				t.Errorf("expected data %v, got %v", tc.expectedData, result)
			}

			if stale != tc.expectedStale {
				t.Errorf("expected stale %v, got %v", tc.expectedStale, stale)
			}

			if err != tc.expectedErr {
				t.Errorf("expected error %v, got %v", tc.expectedErr, err)
			}
		})
	}
}

// TestPrefixTransformerStaleHandling tests the stale flag handling
func TestPrefixTransformerStaleHandling(t *testing.T) {
	testErr := fmt.Errorf("no match")

	testCases := []struct {
		name           string
		input          []byte
		transformerIdx int
		transformStale bool
		expectedStale  bool
	}{
		{
			name:           "first transformer, not stale from transformer",
			input:          []byte("first:data"),
			transformerIdx: 0,
			transformStale: false,
			expectedStale:  false,
		},
		{
			name:           "first transformer, stale from transformer",
			input:          []byte("first:data"),
			transformerIdx: 0,
			transformStale: true,
			expectedStale:  true,
		},
		{
			name:           "second transformer, not stale from transformer",
			input:          []byte("second:data"),
			transformerIdx: 1,
			transformStale: false,
			expectedStale:  true, // not first transformer
		},
		{
			name:           "second transformer, stale from transformer",
			input:          []byte("second:data"),
			transformerIdx: 1,
			transformStale: true,
			expectedStale:  true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			mock1 := &mockTransformer{
				transformFromStorageResult: []byte("result1"),
				transformFromStorageStale:  tc.transformStale,
			}
			mock2 := &mockTransformer{
				transformFromStorageResult: []byte("result2"),
				transformFromStorageStale:  tc.transformStale,
			}

			transformers := []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: mock1},
				{Prefix: []byte("second:"), Transformer: mock2},
			}

			p := NewPrefixTransformers(testErr, transformers...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

			_, stale, _ := p.TransformFromStorage(ctx, tc.input, nil)

			if stale != tc.expectedStale {
				t.Errorf("expected stale %v, got %v", tc.expectedStale, stale)
			}
		})
	}
}

// TestNewPrefixTransformersCustomError tests custom error handling in NewPrefixTransformers
func TestNewPrefixTransformersCustomError(t *testing.T) {
	testErr := fmt.Errorf("custom error")
	customErr := fmt.Errorf("custom error message")

	transformers := []PrefixTransformer{
		{Prefix: []byte("prefix:"), Transformer: &mockTransformer{}},
	}

	// Test with custom error
	p := NewPrefixTransformers(customErr, transformers...)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	_, _, err := p.TransformFromStorage(ctx, []byte("nomatch:data"), nil)

	if err != customErr {
		t.Errorf("expected custom error, got %v", err)
	}

	// Test with nil error (should use default)
	p2 := NewPrefixTransformers(nil, transformers...)
	_, _, err2 := p2.TransformFromStorage(ctx, []byte("nomatch:data"), nil)

	if err2 == nil {
		t.Fatal("expected error when no prefix matches, got nil")
	}

	expectedMsg := "the provided value does not match any of the supported transformers"
	if err2.Error() != expectedMsg {
		t.Errorf("expected message %q, got %q", expectedMsg, err2.Error())
	}

	// Test error is different from testErr
	if err2 == testErr {
		t.Errorf("error should not be the test error")
	}
}

// TestPrefixTransformerOrderMatters tests that first transformer is used for writes
func TestPrefixTransformerOrderMatters(t *testing.T) {
	testErr := fmt.Errorf("no match")

	mock1 := &mockTransformer{
		transformToStorageResult: []byte("encrypted1"),
	}
	mock2 := &mockTransformer{
		transformToStorageResult: []byte("encrypted2"),
	}

	testCases := []struct {
		name              string
		transformers      []PrefixTransformer
		expectedPrefix    []byte
		expectedData      []byte
		expectedTransform int
	}{
		{
			name: "first transformer is used for write",
			transformers: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: mock1},
				{Prefix: []byte("second:"), Transformer: mock2},
			},
			expectedPrefix:    []byte("first:"),
			expectedData:      []byte("encrypted1"),
			expectedTransform: 0,
		},
		{
			name: "only transformer used for write",
			transformers: []PrefixTransformer{
				{Prefix: []byte("only:"), Transformer: mock1},
			},
			expectedPrefix:    []byte("only:"),
			expectedData:      []byte("encrypted1"),
			expectedTransform: 0,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			p := NewPrefixTransformers(testErr, tc.transformers...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

			result, err := p.TransformToStorage(ctx, []byte("original"), nil)

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			// Result should be prefix + encrypted data
			expectedResult := append(tc.expectedPrefix, tc.expectedData...)
			if !bytes.Equal(result, expectedResult) {
				t.Errorf("expected %v, got %v", expectedResult, result)
			}

			// Verify the correct transformer received the data
			if !bytes.Equal(tc.transformers[tc.expectedTransform].Transformer.(*mockTransformer).recordedToData, []byte("original")) {
				t.Errorf("expected transformer to receive original data")
			}
		})
	}
