			transformerIdx: 0,
			transformStale: true,
			expectedStale:  true,
		},
		{
			name:           "second transformer, not stale from transformer",
			input:          []byte("second:data"),
			transformerIdx: 1,
			transformStale: false,
			expectedStale:  true, // not first transformer
