		outErr   error
		expectOk bool
	}{
		{
			name:     "successful transformation",
			input:    []byte("original"),
			outData:  []byte("transformed"),
			outErr:   nil,
			expectOk: true,
		},
		{
			name:     "transformation with error",
			input:    []byte("original"),
			outData:  nil,
			outErr:   fmt.Errorf("transformation failed"),
			expectOk: false,
		},
		{
			name:     "empty input",
			input:    []byte{},
			outData:  []byte("result"),
			outErr:   nil,
			expectOk: true,
		},
	}

