// TestTransformerRoundTrip tests basic round-trip transformation
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name     string
		input    []byte
		outData  []byte
		outErr   error
		expectOk bool
	}{
		{
			name:     "successful transformation",
			input:    []byte("original"),
			outData:  []byte("transformed"),
			outErr:   nil,
			expectOk: true,
		},
		{
			name:     "transformation with error",
			input:    []byte("original"),
			outData:  nil,
			outErr:   fmt.Errorf("transformation failed"),
			expectOk: false,
		},
		{
			name:     "empty input",
			input:    []byte{},
			outData:  []byte("result"),
			outErr:   nil,
			expectOk: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			mock := &mockTransformer{
				transformFromStorageResult: tc.outData,
				transformFromStorageErr:    tc.outErr,
			}

			result, _, err := mock.TransformFromStorage(context.Background(), tc.input, nil)

			if (err == nil) != tc.expectOk {
				t.Errorf("expected error state %v, got %v", tc.expectOk, err == nil)
			}

			if !bytes.Equal(result, tc.outData) {
				t.Errorf("expected %v, got %v", tc.outData, result)
			}

			if !bytes.Equal(mock.recordedFromData, tc.input) {
				t.Errorf("expected to record input %v, got %v", tc.input, mock.recordedFromData)
			}
		})
	}
}

